    95→    /**
    96→     * If false, style validation will be skipped. Useful in production environment.
    97→     */
    98→    validate?: boolean;
    99→    /**
   100→     * Defines a CSS
   101→     * font-family for locally overriding generation of Chinese, Japanese, and Korean characters.
   102→     * For these characters, font settings from the map's style will be ignored, except for font-weight keywords (light/regular/medium/bold).
   103→     * Set to `false`, to enable font settings from the map's style for these glyph ranges.
   104→     * Forces a full update.
   105→     */
   106→    localIdeographFontFamily?: string | false;
   107→};
   108→
   109→/**
   110→ * Supporting type to add validation to another style related type
   111→ */
