   113→    /**
   114→     * Whether to check if the filter conforms to the MapLibre Style Specification. Disabling validation is a performance optimization that should only be used if you have previously validated the values you will be passing to this function.
   115→     */
   116→    validate?: boolean;
   117→};
   118→
   119→/**
   120→ * Part of {@link Map.setStyle} options, transformStyle is a convenience function that allows to modify a style after it is fetched but before it is committed to the map state.
   121→ *
   122→ * This function exposes previous and next styles, it can be commonly used to support a range of functionalities like:
   123→ *
   124→ * - when previous style carries certain 'state' that needs to be carried over to a new style gracefully;
   125→ * - when a desired style is a certain combination of previous and incoming style;
   126→ * - when an incoming style requires modification based on external state.
   127→ * - when an incoming style uses relative paths, which need to be converted to absolute.
   128→ *
   129→ * @param previous - The current style.
   130→ * @param next - The next style.
   131→ * @returns resulting style that will to be applied to the map
   132→ *
   133→ * @example
   134→ * ```ts
   135→ * map.setStyle('https://demotiles.maplibre.org/style.json', {
   136→ *   transformStyle: (previousStyle, nextStyle) => ({
   137→ *       ...nextStyle,
   138→ *       // make relative sprite path like "../sprite" absolute
   139→ *       sprite: new URL(nextStyle.sprite, "https://demotiles.maplibre.org/styles/osm-bright-gl-style/sprites/").href,
   140→ *       // make relative glyphs path like "../fonts/{fontstack}/{range}.pbf" absolute
   141→ *       glyphs: new URL(nextStyle.glyphs, "https://demotiles.maplibre.org/font/").href,
   142→ *       sources: {
   143→ *           // make relative vector url like "../../" absolute
   144→ *           ...nextStyle.sources.map(source => {
   145→ *              if (source.url) {
   146→ *                  source.url = new URL(source.url, "https://api.maptiler.com/tiles/osm-bright-gl-style/");
   147→ *              }
   148→ *              return source;
   149→ *           }),
   150→ *           // copy a source from previous style
   151→ *           'osm': previousStyle.sources.osm
   152→ *       },
   153→ *       layers: [
   154→ *           // background layer
   155→ *           nextStyle.layers[0],
   156→ *           // copy a layer from previous style
   157→ *           previousStyle.layers[0],
   158→ *           // other layers from the next style
   159→ *           ...nextStyle.layers.slice(1).map(layer => {
   160→ *               // hide the layers we don't need from demotiles style
   161→ *               if (layer.id.startsWith('geolines')) {
   162→ *                   layer.layout = {...layer.layout || {}, visibility: 'none'};
   163→ *               // filter out US polygons
   164→ *               } else if (layer.id.startsWith('coastline') || layer.id.startsWith('countries')) {
   165→ *                   layer.filter = ['!=', ['get', 'ADM0_A3'], 'USA'];
   166→ *               }
   167→ *               return layer;
   168→ *           })
   169→ *       ]
   170→ *   })
   171→ * });
   172→ * ```
   173→ */
   174→export type TransformStyleFunction = (previous: StyleSpecification | undefined, next: StyleSpecification) => StyleSpecification;
   175→
   176→/**
   177→ * The options object related to the {@link Map}'s style related methods
   178→ */
   179→export type StyleSwapOptions = {
   180→    /**
   181→     * If false, force a 'full' update, removing the current style
   182→     * and building the given one instead of attempting a diff-based update.
   183→     */
   184→    diff?: boolean;
   185→    /**
   186→     * TransformStyleFunction is a convenience function
   187→     * that allows to modify a style after it is fetched but before it is committed to the map state. Refer to {@link TransformStyleFunction}.
   188→     */
   189→    transformStyle?: TransformStyleFunction;
   190→};
   191→
   192→/**
   193→ * Specifies a layer to be added to a {@link Style}. In addition to a standard {@link LayerSpecification}
   194→ * or a {@link CustomLayerInterface}, a {@link LayerSpecification} with an embedded {@link SourceSpecification} can also be provided.
   195→ */
   196→export type AddLayerObject = LayerSpecification | (Omit<LayerSpecification, 'source'> & {source: SourceSpecification}) | CustomLayerInterface;
   197→
   198→/**
   199→ * The Style base class
   200→ */
   201→export class Style extends Evented {
   202→    map: Map;
   203→    stylesheet: StyleSpecification;
   204→    dispatcher: Dispatcher;
   205→    imageManager: ImageManager;
   206→    glyphManager: GlyphManager;
   207→    lineAtlas: LineAtlas;
   208→    light: Light;
   209→    projection: Projection | undefined;
   210→    sky: Sky;
   211→
   212→    _frameRequest: AbortController;
   213→    _loadStyleRequest: AbortController;
   214→    _spriteRequest: AbortController;
   215→    _layers: {[_: string]: StyleLayer};
   216→    _serializedLayers: {[_: string]: LayerSpecification};
   217→    _order: Array<string>;
   218→    sourceCaches: {[_: string]: SourceCache};
   219→    zoomHistory: ZoomHistory;
   220→    _loaded: boolean;
   221→    _changed: boolean;
   222→    _updatedSources: {[_: string]: 'clear' | 'reload'};
   223→    _updatedLayers: {[_: string]: true};
   224→    _removedLayers: {[_: string]: StyleLayer};
   225→    _changedImages: {[_: string]: true};
   226→    _glyphsDidChange: boolean;
   227→    _updatedPaintProps: {[layer: string]: true};
   228→    _layerOrderChanged: boolean;
   229→    // image ids of images loaded from style's sprite
   230→    _spritesImagesIds: {[spriteId: string]: string[]};
   231→    // image ids of all images loaded (sprite + user)
   232→    _availableImages: Array<string>;
   233→    _globalState: Record<string, any>;
   234→    crossTileSymbolIndex: CrossTileSymbolIndex;
   235→    pauseablePlacement: PauseablePlacement;
   236→    placement: Placement;
   237→    z: number;
   238→
   239→    constructor(map: Map, options: StyleOptions = {}) {
   240→        super();
   241→
   242→        this.map = map;
   243→        this.dispatcher = new Dispatcher(getGlobalWorkerPool(), map._getMapId());
   244→        this.dispatcher.registerMessageHandler(MessageType.getGlyphs, (mapId, params) => {
   245→            return this.getGlyphs(mapId, params);
   246→        });
   247→        this.dispatcher.registerMessageHandler(MessageType.getImages, (mapId, params) => {
   248→            return this.getImages(mapId, params);
   249→        });
   250→        this.imageManager = new ImageManager();
   251→        this.imageManager.setEventedParent(this);
   252→        this.glyphManager = new GlyphManager(map._requestManager, options.localIdeographFontFamily);
   253→        this.lineAtlas = new LineAtlas(256, 512);
   254→        this.crossTileSymbolIndex = new CrossTileSymbolIndex();
   255→
   256→        this._spritesImagesIds = {};
   257→        this._layers = {};
   258→
   259→        this._order = [];
   260→        this.sourceCaches = {};
   261→        this.zoomHistory = new ZoomHistory();
   262→        this._loaded = false;
   263→        this._availableImages = [];
   264→        this._globalState = {};
   265→
   266→        this._resetUpdates();
   267→
   268→        this.dispatcher.broadcast(MessageType.setReferrer, getReferrer());
   269→        rtlMainThreadPluginFactory().on(RTLPluginLoadedEventName, this._rtlPluginLoaded);
   270→
   271→        this.on('data', (event) => {
   272→            if (event.dataType !== 'source' || event.sourceDataType !== 'metadata') {
   273→                return;
   274→            }
   275→
   276→            const sourceCache = this.sourceCaches[event.sourceId];
   277→            if (!sourceCache) {
   278→                return;
   279→            }
   280→
   281→            const source = sourceCache.getSource();
   282→            if (!source || !source.vectorLayerIds) {
   283→                return;
   284→            }
   285→
   286→            for (const layerId in this._layers) {
   287→                const layer = this._layers[layerId];
   288→                if (layer.source === source.id) {
   289→                    this._validateLayer(layer);
   290→                }
   291→            }
   292→        });
   293→    }
   294→
   295→    _rtlPluginLoaded = () => {
   296→        for (const id in this.sourceCaches) {
   297→            const sourceType = this.sourceCaches[id].getSource().type;
   298→            if (sourceType === 'vector' || sourceType === 'geojson') {
   299→                // Non-vector sources don't have any symbols buckets to reload when the RTL text plugin loads
   300→                // They also load more quickly, so they're more likely to have already displaying tiles
   301→                // that would be unnecessarily booted by the plugin load event
   302→                this.sourceCaches[id].reload(); // Should be a no-op if the plugin loads before any tiles load
   303→            }
   304→        }
   305→    };
   306→
   307→    setGlobalStateProperty(name: string, value: any) {
   308→        this._checkLoaded();
   309→
   310→        const newValue = value === null ?
   311→            this.stylesheet.state?.[name]?.default ?? null :
   312→            value;
   313→
   314→        if (deepEqual(newValue, this._globalState[name])) {
   315→            return this;
   316→        }
   317→
   318→        this._globalState[name] = newValue;
   319→
   320→        const sourceIdsToReload = this._findGlobalStateAffectedSources([name]);
   321→
   322→        for (const id in this.sourceCaches) {
   323→            if (sourceIdsToReload.has(id)) {
   324→                this._reloadSource(id);
   325→                this._changed = true;
   326→            }
   327→        }
   328→    }
   329→
   330→    getGlobalState() {
   331→        return this._globalState;
   332→    }
   333→
   334→    setGlobalState(newStylesheetState: StateSpecification) {
   335→        this._checkLoaded();
   336→
   337→        const changedGlobalStateRefs = [];
   338→
   339→        for (const propertyName in newStylesheetState) {
   340→            const didChange = !deepEqual(this._globalState[propertyName], newStylesheetState[propertyName].default);
   341→
   342→            if (didChange) {
   343→                changedGlobalStateRefs.push(propertyName);
   344→                this._globalState[propertyName] = newStylesheetState[propertyName].default;
   345→            }
   346→        }
   347→
   348→        const sourceIdsToReload = this._findGlobalStateAffectedSources(changedGlobalStateRefs);
   349→
   350→        for (const id in this.sourceCaches) {
   351→            if (sourceIdsToReload.has(id)) {
   352→                this._reloadSource(id);
   353→                this._changed = true;
   354→            }
   355→        }
   356→    }
   357→
   358→    /**
   359→     * Find all sources that are affected by the global state changes.
   360→     * For example, if a layer filter uses global-state expression, this function will return the source id of that layer.
   361→     */
   362→    _findGlobalStateAffectedSources(globalStateRefs: string[]) {
   363→        if (globalStateRefs.length === 0) {
   364→            return new Set<string>();
   365→        }
   366→
   367→        const sourceIdsToReload = new Set<string>();
   368→
   369→        for (const layerId in this._layers) {
   370→            const layer = this._layers[layerId];
   371→            const layoutAffectingGlobalStateRefs = layer.getLayoutAffectingGlobalStateRefs();
   372→
   373→            for (const ref of globalStateRefs) {
   374→                if (layoutAffectingGlobalStateRefs.has(ref)) {
   375→                    sourceIdsToReload.add(layer.source);
   376→                }
   377→            }
   378→        }
   379→
   380→        return sourceIdsToReload;
   381→    }
   382→
   383→    loadURL(url: string, options: StyleSwapOptions & StyleSetterOptions = {}, previousStyle?: StyleSpecification) {
   384→        this.fire(new Event('dataloading', {dataType: 'style'}));
   385→
   386→        options.validate = typeof options.validate === 'boolean' ?
   387→            options.validate : true;
   388→
   389→        const request = this.map._requestManager.transformRequest(url, ResourceType.Style);
   390→        this._loadStyleRequest = new AbortController();
   391→        const abortController = this._loadStyleRequest;
   392→        getJSON<StyleSpecification>(request, this._loadStyleRequest).then((response) => {
   393→            this._loadStyleRequest = null;
   394→            this._load(response.data, options, previousStyle);
   395→        }).catch((error) => {
   396→            this._loadStyleRequest = null;
   397→            if (error && !abortController.signal.aborted) { // ignore abort
   398→                this.fire(new ErrorEvent(error));
   399→            }
   400→        });
   401→    }
   402→
   403→    loadJSON(json: StyleSpecification, options: StyleSetterOptions & StyleSwapOptions = {}, previousStyle?: StyleSpecification) {
   404→        this.fire(new Event('dataloading', {dataType: 'style'}));
   405→
   406→        this._frameRequest = new AbortController();
   407→        browser.frameAsync(this._frameRequest).then(() => {
   408→            this._frameRequest = null;
   409→            options.validate = options.validate !== false;
   410→            this._load(json, options, previousStyle);
   411→        }).catch(() => {}); // ignore abort
   412→    }
   413→
   414→    loadEmpty() {
   415→        this.fire(new Event('dataloading', {dataType: 'style'}));
   416→        this._load(empty, {validate: false});
   417→    }
   418→
   419→    _load(json: StyleSpecification, options: StyleSwapOptions & StyleSetterOptions, previousStyle?: StyleSpecification) {
   420→        const nextState = options.transformStyle ? options.transformStyle(previousStyle, json) : json;
   421→        if (options.validate && emitValidationErrors(this, validateStyle(nextState))) {
   422→            return;
   423→        }
   424→
   425→        this._loaded = true;
   426→        this.stylesheet = nextState;
   427→
   428→        for (const id in nextState.sources) {
   429→            this.addSource(id, nextState.sources[id], {validate: false});
   430→        }
   431→
   432→        if (nextState.sprite) {
   433→            this._loadSprite(nextState.sprite);
   434→        } else {
   435→            this.imageManager.setLoaded(true);
   436→        }
   437→
   438→        this.glyphManager.setURL(nextState.glyphs);
   439→        this._createLayers();
   440→
   441→        this.light = new Light(this.stylesheet.light);
   442→        this._setProjectionInternal(this.stylesheet.projection?.type || 'mercator');
   443→
   444→        this.sky = new Sky(this.stylesheet.sky);
   445→
   446→        this.map.setTerrain(this.stylesheet.terrain ?? null);
   447→
   448→        this.setGlobalState(this.stylesheet.state ?? null);
   449→
   450→        this.fire(new Event('data', {dataType: 'style'}));
   451→        this.fire(new Event('style.load'));
   452→    }
   453→
   454→    private _createLayers() {
   455→        const dereferencedLayers = derefLayers(this.stylesheet.layers);
   456→
   457→        // Broadcast layers to workers first, so that expensive style processing (createStyleLayer)
   458→        // can happen in parallel on both main and worker threads.
   459→        this.dispatcher.broadcast(MessageType.setLayers, dereferencedLayers);
   460→
   461→        this._order = dereferencedLayers.map((layer) => layer.id);
   462→        this._layers = {};
   463→
   464→        // reset serialization field, to be populated only when needed
   465→        this._serializedLayers = null;
   466→        for (const layer of dereferencedLayers) {
   467→            const styledLayer = createStyleLayer(layer);
   468→            styledLayer.setEventedParent(this, {layer: {id: layer.id}});
   469→            this._layers[layer.id] = styledLayer;
   470→        }
   471→    }
   472→
   473→    _loadSprite(sprite: SpriteSpecification, isUpdate: boolean = false, completion: (err: Error) => void = undefined) {
   474→        this.imageManager.setLoaded(false);
   475→
   476→        this._spriteRequest = new AbortController();
   477→        let err: Error;
   478→        loadSprite(sprite, this.map._requestManager, this.map.getPixelRatio(), this._spriteRequest).then((images) => {
   479→            this._spriteRequest = null;
   480→            if (images) {
   481→                for (const spriteId in images) {
   482→                    this._spritesImagesIds[spriteId] = [];
   483→
   484→                    // remove old sprite's loaded images (for the same sprite id) that are not in new sprite
   485→                    const imagesToRemove = this._spritesImagesIds[spriteId] ? this._spritesImagesIds[spriteId].filter(id => !(id in images)) : [];
   486→                    for (const id of imagesToRemove) {
   487→                        this.imageManager.removeImage(id);
   488→                        this._changedImages[id] = true;
   489→                    }
   490→
   491→                    for (const id in images[spriteId]) {
   492→                        // don't prefix images of the "default" sprite
   493→                        const imageId = spriteId === 'default' ? id : `${spriteId}:${id}`;
   494→                        // save all the sprite's images' ids to be able to delete them in `removeSprite`
   495→                        this._spritesImagesIds[spriteId].push(imageId);
   496→                        if (imageId in this.imageManager.images) {
   497→                            this.imageManager.updateImage(imageId, images[spriteId][id], false);
   498→                        } else {
   499→                            this.imageManager.addImage(imageId, images[spriteId][id]);
   500→                        }
   501→
   502→                        if (isUpdate) {
   503→                            this._changedImages[imageId] = true;
   504→                        }
   505→                    }
   506→                }
   507→            }
   508→        }).catch((error) => {
   509→            this._spriteRequest = null;
   510→            err = error;
   511→            this.fire(new ErrorEvent(err));
   512→        }).finally(() => {
   513→            this.imageManager.setLoaded(true);
   514→            this._availableImages = this.imageManager.listImages();
   515→
   516→            if (isUpdate) {
   517→                this._changed = true;
   518→            }
   519→
   520→            this.dispatcher.broadcast(MessageType.setImages, this._availableImages);
   521→            this.fire(new Event('data', {dataType: 'style'}));
   522→
   523→            if (completion) {
   524→                completion(err);
   525→            }
   526→        });
   527→    }
   528→
   529→    _unloadSprite() {
   530→        for (const id of Object.values(this._spritesImagesIds).flat()) {
   531→            this.imageManager.removeImage(id);
   532→            this._changedImages[id] = true;
   533→        }
   534→
   535→        this._spritesImagesIds = {};
   536→        this._availableImages = this.imageManager.listImages();
   537→        this._changed = true;
   538→        this.dispatcher.broadcast(MessageType.setImages, this._availableImages);
   539→        this.fire(new Event('data', {dataType: 'style'}));
   540→    }
   541→
   542→    _validateLayer(layer: StyleLayer) {
   543→        const sourceCache = this.sourceCaches[layer.source];
   544→        if (!sourceCache) {
   545→            return;
   546→        }
   547→
   548→        const sourceLayer = layer.sourceLayer;
   549→        if (!sourceLayer) {
   550→            return;
   551→        }
   552→
   553→        const source = sourceCache.getSource();
   554→        if (source.type === 'geojson' || (source.vectorLayerIds && source.vectorLayerIds.indexOf(sourceLayer) === -1)) {
   555→            this.fire(new ErrorEvent(new Error(
   556→                `Source layer "${sourceLayer}" ` +
   557→                `does not exist on source "${source.id}" ` +
   558→                `as specified by style layer "${layer.id}".`
   559→            )));
   560→        }
   561→    }
   562→
   563→    loaded() {
   564→        if (!this._loaded)
   565→            return false;
   566→
   567→        if (Object.keys(this._updatedSources).length)
   568→            return false;
   569→
   570→        for (const id in this.sourceCaches)
   571→            if (!this.sourceCaches[id].loaded())
   572→                return false;
   573→
   574→        if (!this.imageManager.isLoaded())
   575→            return false;
   576→
   577→        return true;
   578→    }
   579→
   580→    /**
   581→     * @hidden
   582→     * take an array of string IDs, and based on this._layers, generate an array of LayerSpecification
   583→     * @param ids - an array of string IDs, for which serialized layers will be generated. If omitted, all serialized layers will be returned
   584→     * @param returnClose - if true, return a clone of the layer object
   585→     * @returns generated result
   586→     */
   587→    private _serializeByIds(ids: Array<string>, returnClone: boolean = false): Array<LayerSpecification> {
   588→
   589→        const serializedLayersDictionary = this._serializedAllLayers();
   590→        if (!ids || ids.length === 0) {
   591→            return returnClone ? Object.values(clone(serializedLayersDictionary)) : Object.values(serializedLayersDictionary);
   592→        }
   593→
   594→        const serializedLayers = [];
   595→        for (const id of ids) {
   596→            // this check will skip all custom layers
   597→            if (serializedLayersDictionary[id]) {
   598→                const toPush = returnClone ? clone(serializedLayersDictionary[id]) : serializedLayersDictionary[id];
   599→                serializedLayers.push(toPush);
   600→            }
   601→        }
   602→
   603→        return serializedLayers;
   604→    }
   605→
   606→    /**
   607→     * @hidden
   608→     * Lazy initialization of this._serializedLayers dictionary and return it
   609→     * @returns this._serializedLayers dictionary
   610→     */
   611→    private _serializedAllLayers(): {[_: string]: LayerSpecification} {
   612→        let serializedLayers = this._serializedLayers;
   613→        if (serializedLayers) {
   614→            return serializedLayers;
   615→        }
   616→
   617→        serializedLayers = this._serializedLayers = {};
   618→        const allLayerIds: string [] = Object.keys(this._layers);
   619→        for (const layerId of allLayerIds) {
   620→            const layer = this._layers[layerId];
   621→            if (layer.type !== 'custom') {
   622→                serializedLayers[layerId] = layer.serialize();
   623→            }
   624→        }
   625→
   626→        return serializedLayers;
   627→    }
   628→
   629→    hasTransitions() {
   630→        if (this.light?.hasTransition()) {
   631→            return true;
   632→        }
   633→
   634→        if (this.sky?.hasTransition()) {
   635→            return true;
   636→        }
   637→
   638→        if (this.projection?.hasTransition()) {
   639→            return true;
   640→        }
   641→
   642→        for (const id in this.sourceCaches) {
   643→            if (this.sourceCaches[id].hasTransition()) {
   644→                return true;
   645→            }
   646→        }
   647→
   648→        for (const id in this._layers) {
   649→            if (this._layers[id].hasTransition()) {
   650→                return true;
   651→            }
   652→        }
   653→
   654→        return false;
   655→    }
   656→
   657→    _checkLoaded() {
   658→        if (!this._loaded) {
   659→            throw new Error('Style is not done loading.');
   660→        }
   661→    }
   662→
   663→    /**
   664→     * @internal
   665→     * Apply queued style updates in a batch and recalculate zoom-dependent paint properties.
   666→     */
   667→    update(parameters: EvaluationParameters) {
   668→        if (!this._loaded) {
   669→            return;
   670→        }
   671→
   672→        const changed = this._changed;
   673→        if (changed) {
   674→            const updatedIds = Object.keys(this._updatedLayers);
   675→            const removedIds = Object.keys(this._removedLayers);
   676→
   677→            if (updatedIds.length || removedIds.length) {
   678→                this._updateWorkerLayers(updatedIds, removedIds);
   679→            }
   680→            for (const id in this._updatedSources) {
   681→                const action = this._updatedSources[id];
   682→
   683→                if (action === 'reload') {
   684→                    this._reloadSource(id);
   685→                } else if (action === 'clear') {
   686→                    this._clearSource(id);
   687→                } else {
   688→                    throw new Error(`Invalid action ${action}`);
   689→                }
   690→            }
   691→
   692→            this._updateTilesForChangedImages();
   693→            this._updateTilesForChangedGlyphs();
   694→
   695→            for (const id in this._updatedPaintProps) {
   696→                this._layers[id].updateTransitions(parameters);
   697→            }
   698→
   699→            this.light.updateTransitions(parameters);
   700→            this.sky.updateTransitions(parameters);
   701→
   702→            this._resetUpdates();
   703→        }
   704→
   705→        const sourcesUsedBefore = {};
   706→
   707→        // save 'used' status to sourcesUsedBefore object and reset all sourceCaches 'used' field to false
   708→        for (const sourceCacheId in this.sourceCaches) {
   709→            const sourceCache = this.sourceCaches[sourceCacheId];
   710→
   711→            // sourceCache.used could be undefined, and sourcesUsedBefore[sourceCacheId] is also 'undefined'
   712→            sourcesUsedBefore[sourceCacheId] = sourceCache.used;
   713→            sourceCache.used = false;
   714→        }
   715→
   716→        // loop all layers and find layers that are not hidden at parameters.zoom
   717→        // and set used to true in sourceCaches dictionary for the sources of these layers
   718→        for (const layerId of this._order) {
   719→            const layer = this._layers[layerId];
   720→
   721→            layer.recalculate(parameters, this._availableImages);
   722→            if (!layer.isHidden(parameters.zoom) && layer.source) {
   723→                this.sourceCaches[layer.source].used = true;
   724→            }
   725→        }
   726→
   727→        // cross check sourcesUsedBefore against updated this.sourceCaches dictionary
   728→        // if "used" field is different fire visibility event
   729→        for (const sourcesUsedBeforeId in sourcesUsedBefore) {
   730→            const sourceCache = this.sourceCaches[sourcesUsedBeforeId];
   731→
   732→            // (undefine !== false) will evaluate to true and fire an useless visibility event
   733→            // need force "falsy" values to boolean to avoid the case above
   734→            if (!!sourcesUsedBefore[sourcesUsedBeforeId] !== !!sourceCache.used) {
   735→                sourceCache.fire(new Event('data',
   736→                    {
   737→                        sourceDataType: 'visibility',
   738→                        dataType: 'source',
   739→                        sourceId: sourcesUsedBeforeId
   740→                    }));
   741→            }
   742→        }
   743→
   744→        this.light.recalculate(parameters);
   745→        this.sky.recalculate(parameters);
   746→        this.projection.recalculate(parameters);
   747→        this.z = parameters.zoom;
   748→
   749→        if (changed) {
   750→            this.fire(new Event('data', {dataType: 'style'}));
   751→        }
   752→    }
   753→
   754→    /*
   755→     * Apply any queued image changes.
   756→     */
   757→    _updateTilesForChangedImages() {
   758→        const changedImages = Object.keys(this._changedImages);
   759→        if (changedImages.length) {
   760→            for (const name in this.sourceCaches) {
   761→                this.sourceCaches[name].reloadTilesForDependencies(['icons', 'patterns'], changedImages);
   762→            }
   763→            this._changedImages = {};
   764→        }
   765→    }
   766→
   767→    _updateTilesForChangedGlyphs() {
   768→        if (this._glyphsDidChange) {
   769→            for (const name in this.sourceCaches) {
   770→                this.sourceCaches[name].reloadTilesForDependencies(['glyphs'], ['']);
   771→            }
   772→            this._glyphsDidChange = false;
   773→        }
   774→    }
   775→
   776→    _updateWorkerLayers(updatedIds: Array<string>, removedIds: Array<string>) {
   777→        this.dispatcher.broadcast(MessageType.updateLayers, {
   778→            layers: this._serializeByIds(updatedIds, false),
   779→            removedIds
   780→        });
   781→    }
   782→
   783→    _resetUpdates() {
   784→        this._changed = false;
   785→
   786→        this._updatedLayers = {};
