   796→    /**
   797→     * Update this style's state to match the given style JSON, performing only
   798→     * the necessary mutations.
   799→     *
   800→     * May throw an Error ('Unimplemented: METHOD') if the mapbox-gl-style-spec
   801→     * diff algorithm produces an operation that is not supported.
   802→     *
   803→     * @returns true if any changes were made; false otherwise
   804→     */
   805→    setState(nextState: StyleSpecification, options: StyleSwapOptions & StyleSetterOptions = {}) {
   806→        this._checkLoaded();
   807→
   808→        const serializedStyle =  this.serialize();
   809→        nextState = options.transformStyle ? options.transformStyle(serializedStyle, nextState) : nextState;
   810→        const validate = options.validate ?? true;
   811→        if (validate && emitValidationErrors(this, validateStyle(nextState))) return false;
   812→
   813→        nextState = clone(nextState);
   814→        nextState.layers = derefLayers(nextState.layers);
   815→
   816→        const changes = diffStyles(serializedStyle, nextState);
   817→        const operations = this._getOperationsToPerform(changes);
   818→
   819→        if (operations.unimplemented.length > 0) {
   820→            throw new Error(`Unimplemented: ${operations.unimplemented.join(', ')}.`);
   821→        }
   822→
   823→        if (operations.operations.length === 0) {
   824→            return false;
   825→        }
   826→
   827→        for (const styleChangeOperation of operations.operations) {
   828→            styleChangeOperation();
   829→        }
   830→
   831→        this.stylesheet = nextState;
   832→
   833→        // reset serialization field, to be populated only when needed
   834→        this._serializedLayers = null;
   835→
   836→        return true;
   837→    }
   838→
   839→    _getOperationsToPerform(diff: DiffCommand<DiffOperations>[]) {
   840→        const operations: Function[] = [];
   841→        const unimplemented: string[] = [];
   842→        for (const op of diff) {
   843→            switch (op.command) {
   844→                case 'setCenter':
   845→                case 'setZoom':
   846→                case 'setBearing':
   847→                case 'setPitch':
   848→                case 'setRoll':
   849→                    continue;
   850→                case 'addLayer':
   851→                    operations.push(() => this.addLayer.apply(this, op.args));
   852→                    break;
   853→                case 'removeLayer':
   854→                    operations.push(() => this.removeLayer.apply(this, op.args));
   855→                    break;
   856→                case 'setPaintProperty':
   857→                    operations.push(() => this.setPaintProperty.apply(this, op.args));
   858→                    break;
   859→                case 'setLayoutProperty':
   860→                    operations.push(() => this.setLayoutProperty.apply(this, op.args));
   861→                    break;
   862→                case 'setFilter':
   863→                    operations.push(() => this.setFilter.apply(this, op.args));
   864→                    break;
   865→                case 'addSource':
   866→                    operations.push(() => this.addSource.apply(this, op.args));
   867→                    break;
   868→                case 'removeSource':
   869→                    operations.push(() => this.removeSource.apply(this, op.args));
   870→                    break;
   871→                case 'setLayerZoomRange':
   872→                    operations.push(() => this.setLayerZoomRange.apply(this, op.args));
   873→                    break;
   874→                case 'setLight':
   875→                    operations.push(() => this.setLight.apply(this, op.args));
   876→                    break;
   877→                case 'setGeoJSONSourceData':
   878→                    operations.push(() => this.setGeoJSONSourceData.apply(this, op.args));
   879→                    break;
   880→                case 'setGlyphs':
   881→                    operations.push(() => this.setGlyphs.apply(this, op.args));
   882→                    break;
   883→                case 'setSprite':
   884→                    operations.push(() => this.setSprite.apply(this, op.args));
   885→                    break;
   886→                case 'setTerrain':
   887→                    operations.push(() => this.map.setTerrain.apply(this, op.args));
   888→                    break;
   889→                case 'setSky':
   890→                    operations.push(() => this.setSky.apply(this, op.args));
   891→                    break;
   892→                case 'setProjection':
   893→                    this.setProjection.apply(this, op.args);
   894→                    break;
   895→                case 'setGlobalState':
   896→                    operations.push(() => this.setGlobalState.apply(this, op.args));
   897→                    break;
   898→                case 'setTransition':
   899→                    operations.push(() => {});
   900→                    break;
   901→                default:
   902→                    unimplemented.push(op.command);
   903→                    break;
   904→            }
   905→        }
   906→        return {
   907→            operations,
   908→            unimplemented
   909→        };
   910→    }
