  1406→            version: myStyleSheet.version,
  1407→            name: myStyleSheet.name,
  1408→            metadata: myStyleSheet.metadata,
  1409→            light: myStyleSheet.light,
  1410→            sky: myStyleSheet.sky,
  1411→            center: myStyleSheet.center,
