  1426→    _updateLayer(layer: StyleLayer) {
  1427→        this._updatedLayers[layer.id] = true;
  1428→        if (layer.source && !this._updatedSources[layer.source] &&
  1429→            //Skip for raster layers (https://github.com/mapbox/mapbox-gl-js/issues/7865)
  1430→            this.sourceCaches[layer.source].getSource().type !== 'raster') {
  1431→            this._updatedSources[layer.source] = 'reload';
  1432→            this.sourceCaches[layer.source].pause();
  1433→        }
  1434→
  1435→        // upon updating, serialized layer dictionary should be reset.
  1436        // When needed, it will be populated with the correct copy again.
  1437→        this._serializedLayers = null;
  1438→        this._changed = true;
