  1440→
  1441→    _flattenAndSortRenderedFeatures(sourceResults: QueryRenderedFeaturesResults[]): MapGeoJSONFeature[] {
  1442→        // Feature order is complicated.
  1443→        // The order between features in two 2D layers is always determined by layer order.
  1444→        // The order between features in two 3D layers is always determined by depth.
  1445→        // The order between a feature in a 2D layer and a 3D layer is tricky:
  1446→        //      Most often layer order determines the feature order in this case. If
  1447→        //      a line layer is above a extrusion layer the line feature will be rendered
  1448→        //      above the extrusion. If the line layer is below the extrusion layer,
  1449→        //      it will be rendered below it.
  1450→        //
  1451→        //      There is a weird case though.
  1452→        //      You have layers in this order: extrusion_layer_a, line_layer, extrusion_layer_b
  1453→        //      Each layer has a feature that overlaps the other features.
  1454→        //      The feature in extrusion_layer_a is closer than the feature in extrusion_layer_b so it is rendered above.
  1455→        //      The feature in line_layer is rendered above extrusion_layer_a.
  1456→        //      This means that that the line_layer feature is above the extrusion_layer_b feature despite
  1457→        //      it being in an earlier layer.
  1458→
  1459→        const isLayer3D = layerId => this._layers[layerId].type === 'fill-extrusion';
  1460→
  1461→        const layerIndex = {};
  1462→        const features3D: QueryRenderedFeaturesResultsItem[] = [];
  1463→        for (let l = this._order.length - 1; l >= 0; l--) {
  1464→            const layerId = this._order[l];
  1465→            if (isLayer3D(layerId)) {
  1466→                layerIndex[layerId] = l;
  1467→                for (const sourceResult of sourceResults) {
  1468→                    const layerFeatures = sourceResult[layerId];
  1469→                    if (layerFeatures) {
  1470→                        for (const featureWrapper of layerFeatures) {
  1471→                            features3D.push(featureWrapper);
  1472→                        }
  1473→                    }
  1474→                }
  1475→            }
  1476→        }
  1477→
  1478→        features3D.sort((a, b) => {
  1479→            return (b.intersectionZ as number) - (a.intersectionZ as number);
  1480→        });
  1481→
  1482→        const features: MapGeoJSONFeature[] = [];
  1483→        for (let l = this._order.length - 1; l >= 0; l--) {
  1484→            const layerId = this._order[l];
  1485→
  1486→            if (isLayer3D(layerId)) {
  1487→                // add all 3D features that are in or above the current layer
  1488→                for (let i = features3D.length - 1; i >= 0; i--) {
  1489→                    const topmost3D = features3D[i].feature;
  1490→                    if (layerIndex[topmost3D.layer.id] < l) break;
  1491→                    features.push(topmost3D);
  1492→                    features3D.pop();
  1493→                }
  1494→            } else {
  1495→                for (const sourceResult of sourceResults) {
  1496→                    const layerFeatures = sourceResult[layerId];
  1497→                    if (layerFeatures) {
  1498→                        for (const featureWrapper of layerFeatures) {
  1499→                            features.push(featureWrapper.feature);
  1500→                        }
  1501→                    }
  1502→                }
  1503→            }
  1504→        }
  1505→
  1506→        return features;
  1507→    }
