  1509→    queryRenderedFeatures(queryGeometry: Point[], params: QueryRenderedFeaturesOptions, transform: IReadonlyTransform): MapGeoJSONFeature[] {
  1510→        if (params && params.filter) {
  1511→            this._validate(validateStyle.filter, 'queryRenderedFeatures.filter', params.filter, null, params);
  1512→        }
  1513→
  1514→        const includedSources = {};
  1515→        if (params && params.layers) {
  1516→            const isArrayOrSet = Array.isArray(params.layers) || params.layers instanceof Set;
  1517→            if (!isArrayOrSet) {
  1518→                this.fire(new ErrorEvent(new Error('parameters.layers must be an Array or a Set of strings')));
  1519→                return [];
  1520→            }
  1521→            for (const layerId of params.layers) {
  1522→                const layer = this._layers[layerId];
  1523→                if (!layer) {
  1524→                    // this layer is not in the style.layers array
  1525→                    this.fire(new ErrorEvent(new Error(`The layer '${layerId}' does not exist in the map's style and cannot be queried for features.`)));
  1526→                    return [];
  1527→                }
  1528→                includedSources[layer.source] = true;
  1529→            }
  1530→        }
  1531→
  1532→        const sourceResults: QueryRenderedFeaturesResults[] = [];
  1533→
  1534→        params.availableImages = this._availableImages;
  1535→
  1536→        // LayerSpecification is serialized StyleLayer, and this casting is safe.
  1537→        const serializedLayers = this._serializedAllLayers() as {[_: string]: StyleLayer};
  1538→
  1539→        const layersAsSet = params.layers instanceof Set ? params.layers : Array.isArray(params.layers) ? new Set(params.layers) : null;
  1540→        const paramsStrict: QueryRenderedFeaturesOptionsStrict = {
  1541→            ...params,
  1542→            layers: layersAsSet,
  1543→        };
  1544→
  1545→        for (const id in this.sourceCaches) {
  1546→            if (params.layers && !includedSources[id]) continue;
  1547→            sourceResults.push(
  1548→                queryRenderedFeatures(
  1549→                    this.sourceCaches[id],
  1550→                    this._layers,
  1551→                    serializedLayers,
  1552→                    queryGeometry,
  1553→                    paramsStrict,
  1554→                    transform,
  1555→                    this.map.terrain ?
  1556→                        (id: OverscaledTileID, x: number, y: number) =>
  1557→                            this.map.terrain.getElevation(id, x, y) :
  1558→                        undefined)
  1559→            );
  1560→        }
  1561→
  1562→        if (this.placement) {
  1563→            // If a placement has run, query against its CollisionIndex
  1564→            // for symbol results, and treat it as an extra source to merge
  1565→            sourceResults.push(
  1566→                queryRenderedSymbols(
  1567→                    this._layers,
  1568→                    serializedLayers,
  1569→                    this.sourceCaches,
  1570→                    queryGeometry,
  1571→                    paramsStrict,
  1572→                    this.placement.collisionIndex,
  1573→                    this.placement.retainedQueryData)
  1574→            );
  1575→        }
  1576→
  1577→        return this._flattenAndSortRenderedFeatures(sourceResults);
  1578→    }
