  1696→    _remove(mapRemoved: boolean = true) {
  1697→        if (this._frameRequest) {
  1698→            this._frameRequest.abort();
  1699→            this._frameRequest = null;
  1700→        }
  1701→        if (this._loadStyleRequest) {
  1702→            this._loadStyleRequest.abort();
  1703→            this._loadStyleRequest = null;
  1704→        }
  1705→        if (this._spriteRequest) {
  1706→            this._spriteRequest.abort();
  1707→            this._spriteRequest = null;
  1708→        }
  1709→        rtlMainThreadPluginFactory().off(RTLPluginLoadedEventName, this._rtlPluginLoaded);
  1710→        for (const layerId in this._layers) {
  1711→            const layer: StyleLayer = this._layers[layerId];
  1712→            layer.setEventedParent(null);
  1713→        }
  1714→        for (const id in this.sourceCaches) {
  1715→            const sourceCache = this.sourceCaches[id];
  1716→            sourceCache.setEventedParent(null);
  1717→            sourceCache.onRemove(this.map);
  1718→        }
  1719→        this.imageManager.setEventedParent(null);
  1720→        this.setEventedParent(null);
  1721→        if (mapRemoved) {
  1722→            this.dispatcher.broadcast(MessageType.removeMap, undefined);
  1723→        }
  1724→        this.dispatcher.remove(mapRemoved);
  1725→    }
