  1748→    _updatePlacement(transform: ITransform, showCollisionBoxes: boolean, fadeDuration: number, crossSourceCollisions: boolean, forceFullPlacement: boolean = false) {
  1749→        let symbolBucketsChanged = false;
  1750→        let placementCommitted = false;
  1751→
  1752→        const layerTiles = {};
  1753→
  1754→        for (const layerID of this._order) {
  1755→            const styleLayer = this._layers[layerID];
  1756→            if (styleLayer.type !== 'symbol') continue;
  1757→
  1758→            if (!layerTiles[styleLayer.source]) {
  1759→                const sourceCache = this.sourceCaches[styleLayer.source];
  1760→                layerTiles[styleLayer.source] = sourceCache.getRenderableIds(true)
  1761→                    .map((id) => sourceCache.getTileByID(id))
  1762→                    .sort((a, b) => (b.tileID.overscaledZ - a.tileID.overscaledZ) || (a.tileID.isLessThan(b.tileID) ? -1 : 1));
  1763→            }
  1764→
  1765→            const layerBucketsChanged = this.crossTileSymbolIndex.addLayer(styleLayer, layerTiles[styleLayer.source], transform.center.lng);
  1766→            symbolBucketsChanged = symbolBucketsChanged || layerBucketsChanged;
  1767→        }
  1768→        this.crossTileSymbolIndex.pruneUnusedLayers(this._order);
  1769→
  1770→        // Anything that changes our "in progress" layer and tile indices requires us
  1771→        // to start over. When we start over, we do a full placement instead of incremental
  1772→        // to prevent starvation.
  1773→        // We need to restart placement to keep layer indices in sync.
  1774→        // Also force full placement when fadeDuration === 0 to ensure that newly loaded
  1775→        // tiles will fully display symbols in their first frame
  1776→        forceFullPlacement = forceFullPlacement || this._layerOrderChanged || fadeDuration === 0;
  1777→
  1778→        if (forceFullPlacement || !this.pauseablePlacement || (this.pauseablePlacement.isDone() && !this.placement.stillRecent(browser.now(), transform.zoom))) {
  1779→            this.pauseablePlacement = new PauseablePlacement(transform, this.map.terrain, this._order, forceFullPlacement, showCollisionBoxes, fadeDuration, crossSourceCollisions, this.placement);
  1780→            this._layerOrderChanged = false;
  1781→        }
  1782→
  1783→        if (this.pauseablePlacement.isDone()) {
  1784→            // the last placement finished running, but the next one hasn’t
  1785→            // started yet because of the `stillRecent` check immediately
  1786→            // above, so mark it stale to ensure that we request another
  1787→            // render frame
  1788→            this.placement.setStale();
  1789→        } else {
  1790→            this.pauseablePlacement.continuePlacement(this._order, this._layers, layerTiles);
  1791→
  1792→            if (this.pauseablePlacement.isDone()) {
  1793→                this.placement = this.pauseablePlacement.commit(browser.now());
  1794→                placementCommitted = true;
  1795→            }
  1796→
  1797→            if (symbolBucketsChanged) {
  1798→                // since the placement gets split over multiple frames it is possible
  1799→                // these buckets were processed before they were changed and so the
  1800→                // placement is already stale while it is in progress
  1801→                this.pauseablePlacement.placement.setStale();
  1802→            }
  1803→        }
  1804→
  1805→        if (placementCommitted || symbolBucketsChanged) {
  1806→            for (const layerID of this._order) {
  1807→                const styleLayer = this._layers[layerID];
  1808→                if (styleLayer.type !== 'symbol') continue;
  1809→                this.placement.updateLayerOpacities(styleLayer, layerTiles[styleLayer.source]);
  1810→            }
  1811→        }
  1812→
  1813→        // needsRender is false when we have just finished a placement that didn't change the visibility of any symbols
  1814→        const needsRerender = !this.pauseablePlacement.isDone() || this.placement.hasTransitions(browser.now());
  1815→        return needsRerender;
  1816→    }
